import{_ as e,o as t,c as o,ag as a}from"./chunks/framework.CTpQozEL.js";const d=JSON.parse('{"title":"기능","description":"채널, 라우팅, 미디어, UX에 걸친 OpenClaw 기능.","frontmatter":{"title":"기능","description":"채널, 라우팅, 미디어, UX에 걸친 OpenClaw 기능."},"headers":[],"relativePath":"concepts/features.md","filePath":"concepts/features.md","lastUpdated":null}'),i={name:"concepts/features.md"};function r(s,l,n,c,p,u){return t(),o("div",null,[...l[0]||(l[0]=[a('<h1 id="기능" tabindex="-1">기능 <a class="header-anchor" href="#기능" aria-label="Permalink to &quot;기능&quot;">​</a></h1><h2 id="하이라이트" tabindex="-1">하이라이트 <a class="header-anchor" href="#하이라이트" aria-label="Permalink to &quot;하이라이트&quot;">​</a></h2><blockquote><p><strong>채널</strong> 단일 게이트웨이로 Discord, iMessage, Signal, Slack, Telegram, WhatsApp, WebChat 등을 지원합니다.</p></blockquote><blockquote><p><strong>플러그인</strong> 번들 플러그인은 일반 현재 릴리스에서 별도 설치 없이 Matrix, Nextcloud Talk, Nostr, Twitch, Zalo 등을 추가합니다.</p></blockquote><blockquote><p><strong>라우팅</strong> 격리된 세션이 있는 멀티 에이전트 라우팅.</p></blockquote><blockquote><p><strong>미디어</strong> 이미지, 오디오, 비디오, 문서, 이미지/비디오 생성.</p></blockquote><blockquote><p><strong>앱 및 UI</strong> 웹 제어 UI 및 macOS 컴패니언 앱.</p></blockquote><blockquote><p><strong>모바일 노드</strong> 페어링, 음성/채팅, 풍부한 장치 명령을 갖춘 iOS 및 Android 노드.</p></blockquote><h2 id="전체-목록" tabindex="-1">전체 목록 <a class="header-anchor" href="#전체-목록" aria-label="Permalink to &quot;전체 목록&quot;">​</a></h2><p><strong>채널:</strong></p><ul><li>내장 채널: Discord, Google Chat, iMessage (레거시), IRC, Signal, Slack, Telegram, WebChat, WhatsApp</li><li>번들 플러그인 채널: iMessage용 BlueBubbles, Feishu, LINE, Matrix, Mattermost, Microsoft Teams, Nextcloud Talk, Nostr, QQ Bot, Synology Chat, Tlon, Twitch, Zalo, Zalo Personal</li><li>선택적 별도 설치 채널 플러그인: Voice Call 및 WeChat 같은 서드파티 패키지</li><li>서드파티 채널 플러그인으로 게이트웨이를 추가로 확장할 수 있습니다. 예: WeChat</li><li>멘션 기반 활성화를 통한 그룹 채팅 지원</li><li>허용 목록 및 페어링을 통한 DM 보안</li></ul><p><strong>에이전트:</strong></p><ul><li>도구 스트리밍이 있는 임베디드 에이전트 런타임</li><li>워크스페이스 또는 발신자별 격리된 세션이 있는 멀티 에이전트 라우팅</li><li>세션: 직접 채팅은 공유 <code>main</code>으로 통합; 그룹은 격리됨</li><li>긴 응답을 위한 스트리밍 및 청킹</li></ul><p><strong>인증 및 프로바이더:</strong></p><ul><li>35개 이상의 모델 프로바이더 (Anthropic, OpenAI, Google 등)</li><li>OAuth를 통한 구독 인증 (예: OpenAI Codex)</li><li>사용자 지정 및 자체 호스팅 프로바이더 지원 (vLLM, SGLang, Ollama, 및 모든 OpenAI 호환 또는 Anthropic 호환 엔드포인트)</li></ul><p><strong>미디어:</strong></p><ul><li>이미지, 오디오, 비디오, 문서 입출력</li><li>공유 이미지 생성 및 비디오 생성 기능 서피스</li><li>음성 메모 변환</li><li>여러 프로바이더를 통한 텍스트 음성 변환</li></ul><p><strong>앱 및 인터페이스:</strong></p><ul><li>WebChat 및 브라우저 제어 UI</li><li>macOS 메뉴 바 컴패니언 앱</li><li>페어링, Canvas, 카메라, 화면 녹화, 위치, 음성이 있는 iOS 노드</li><li>페어링, 채팅, 음성, Canvas, 카메라, 장치 명령이 있는 Android 노드</li></ul><p><strong>도구 및 자동화:</strong></p><ul><li>브라우저 자동화, exec, 샌드박싱</li><li>웹 검색 (Brave, DuckDuckGo, Exa, Firecrawl, Gemini, Grok, Kimi, MiniMax Search, Ollama Web Search, Perplexity, SearXNG, Tavily)</li><li>크론 잡 및 하트비트 스케줄링</li><li>스킬, 플러그인, 워크플로우 파이프라인 (Lobster)</li></ul>',21)])])}const h=e(i,[["render",r]]);export{d as __pageData,h as default};
